import{_ as t,o as a,c as r,a4 as l}from"./chunks/framework.BybBnFXO.js";const u=JSON.parse('{"title":"Native Elements","description":"","frontmatter":{"title":"Native Elements","mineralGroup":"native-elements"},"headers":[],"relativePath":"mineral-groups/native-elements.md","filePath":"mineral-groups/native-elements.md","lastUpdated":1784177547000}'),n={name:"mineral-groups/native-elements.md"};function i(s,e,o,d,m,c){return a(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="native-elements" tabindex="-1">Native Elements <a class="header-anchor" href="#native-elements" aria-label="Permalink to &quot;Native Elements&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Native-element minerals are crystals of a single element. In gemology, the most important native element is diamond (carbon), formed by sp³-hybridized carbon atoms in a tetrahedral covalent network — the hardest known natural material. Other native elements (gold, silver, platinum) are typically used as ornamental or precious-metal work rather than faceted gems.</p><h2 id="formula-class" tabindex="-1">Formula Class <a class="header-anchor" href="#formula-class" aria-label="Permalink to &quot;Formula Class&quot;">​</a></h2><p>Single-element composition</p><h2 id="crystal-structure" tabindex="-1">Crystal Structure <a class="header-anchor" href="#crystal-structure" aria-label="Permalink to &quot;Crystal Structure&quot;">​</a></h2><p>Atoms occupy lattice positions in characteristic geometries; metallic native elements (gold, silver) form face-centered cubic structures, while non-metals (diamond) form covalent tetrahedral networks.</p><h2 id="representative-gem-species" tabindex="-1">Representative Gem Species <a class="header-anchor" href="#representative-gem-species" aria-label="Permalink to &quot;Representative Gem Species&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gem</th><th>Formula</th><th>Subgroup</th></tr></thead><tbody><tr><td>Diamond / 金刚石</td><td>C</td><td>non-metal</td></tr><tr><td>Gold / 自然金</td><td>Au</td><td>metal</td></tr><tr><td>Silver / 自然银</td><td>Ag</td><td>metal</td></tr><tr><td>Platinum / 自然铂</td><td>Pt</td><td>metal</td></tr><tr><td>Copper / 自然铜</td><td>Cu</td><td>metal</td></tr></tbody></table><p><em>See the <a href="./intro.html">mineral group overview</a>.</em></p>',10)])])}const p=t(n,[["render",i]]);export{u as __pageData,p as default};
